import React, { useState, useEffect } from "react";
import QRCode from "qrcode";
import "./App.css";
import QrCodeScanner from "./QrCodeScanner";

const generateCanvases = (number) => {
  const obj = {};
  new Array(number).fill().forEach((item, index) => {
    obj[`canvas-${index}`] = "";
  });
  return obj;
};

function App() {
  const [text, setText] = useState("");
  const [canvases, setCanvases] = useState(generateCanvases(100));
  const [canvasIndex, setCanvasIndex] = useState(0);
  const [printView, setPrintView] = useState(false);
  const [scanResult, setScanResult] = useState("");

  useEffect(() => {
    if (printView) {
      window.print();
    }
  }, [printView]);

  const generateQrCode = (evt) => {
    evt.preventDefault();
    const canvas = document.getElementById(`canvas-${canvasIndex}`);

    QRCode.toCanvas(canvas, text, function (error) {
      if (error) console.error(error);
      console.log("success!");
      setText("");
      setCanvasIndex((previousCanvasIndex) => previousCanvasIndex + 1);
      setCanvases({
        ...canvases,
        [`canvas-${canvasIndex}`]: text,
      });
    });
  };

  const onQrCodeSuccess = (result) => setScanResult(result);
  const onQrCodeError = (error) => console.error(error);

  const canvasesToBeRendered = Object.keys(canvases).filter(
    (key) => canvases[key].length
  );
  canvasesToBeRendered.push(`canvas-${canvasIndex}`);

  return (
    <div className="App">
      <QrCodeScanner
        config={{
          fps: 10,
          qrBox: 250,
          disableFlip: false,
        }}
        onQrCodeSuccess={onQrCodeSuccess}
        onQrCodeError={null}
        verbose={true}
      />
      <h1>SCAN RESULT: {scanResult}</h1>
      {!printView && (
        <>
          <h1> QR CODE GENERATOR </h1>
          <button
            className="print-page-btn"
            type="button"
            onClick={() => setPrintView(true)}
          >
            Print Page
          </button>
          <form className="form" onSubmit={generateQrCode}>
            <h3>Input text for QR code</h3>
            <div className="input">
              <input
                value={text}
                onChange={(evt) => setText(evt.target.value)}
                placeholder="Product ID"
              />
              <button disabled={!text.length} type="submit">
                Generate
              </button>
            </div>
          </form>
        </>
      )}
      <div className="canvases">
        {canvasesToBeRendered.map((key) => (
          <div
            key={key}
            className={`canvasContainer ${
              !canvases[key].length ? "d-none" : ""
            }`}
          >
            <canvas id={key} className="canvas"></canvas>
            <span>{canvases[key]}</span>
          </div>
        ))}
      </div>
    </div>
  );
}

export default App;
